      {
        "text": "Ji cejnan hez nakim, tenêtiya min eşkere dikin.",
        "author": "Toshihiko Okuya"
      },
      {
        "text": "Min nikaribû barê giyanê xwe bi tena serê xwe hilgirim îşev. Spas bo hatina te.",
        "author": "Zabel Yesayan"
      },
      {
        "text": "Tu sebebê tenêtîya xwe yi. Te kesek wek hemî kesî dîtibû.",
        "author": "Al Pacino"
      },
      {
        "text": "Ez niha bi tenê me, mîna kundekî li ser kavilan...",
        "author": "Zabel Yesayan"
      },
      {
        "text": "Kesê tehma roj, hîv, stêrk, ax û deryayê hiltîne, ne bitenê ye, ne jî bêçare ye.",
        "author": "Epiktetos"
      },
      {
        "text": "Mirovên gelkî qurre, bêdengî û tenêtiyê hildibijêrin.",
        "author": "Anton Chekhov"
      },
      {
        "text": "Dûrketina me ji mirovan, ne ji kerixîn an guherînê ye. tenêtî penageha giyanên westiyayî ye.",
        "author": "Ernest Hemingway"
      },
      {
        "text": "Tenêtî penageha gîyanên westiyayî ye.",
        "author": "Ernest Hemingway"
      },
      {
        "text": "Şev, xwepêşandana tenêtîyê ye.",
        "author": "Albert Camus"
      },
      {
        "text": "Kesên xwedîyê ramanên kûr, di dawiyê de tenêtiyê hildibijêrin.",
        "author": "Schopenhauer"
      },
      {
        "text": "Kesên rojên xwe yên zor û zehmet bi tena serê xwe derbas kirine, tenêtî ji bo wan nabe pirsgirêk.",
        "author": "Bukowski"
      },
      {
        "text": "Jin tenê namîne, tenêtiyê hildibijêre.",
        "author": "Turgut Uyar"
      },
      {
        "text": "Hin birîn hene di jiyanê de, mîna gurrîyê... Ew birînên ku di tenêtiyê de hêdî hêdî gîyan dikeritînin.",
        "author": "Sadiq Hîdayet"
      },
      {
        "text": "Kesên tenêtiya min didizin û nabin hevalek rastîn jî, hîletê min ji wan diçe.",
        "author": "Nietzsche"
      },
      {
        "text": "Herî zêde dema dibêjin ‘tu ne bi tenê yî’ tu hest bi tenêbûna xwe dikî.",
        "author": "Emma Goldman"
      }
